'use client'

import type { Course } from '@/types/contentful';
import { fetchCourseBySlug } from '@/lib/contentful';

type Props = {
  params: { slug: string };
};

function fixImageUrl(url?: string) {
  if (!url) return null;
  if (url.startsWith('//')) return `https:${url}`;
  if (url.startsWith('http')) return url;
  return `https:${url}`;
}

export default async function CoursePage({ params }: Props) {
  const slug = params?.slug;
  const course: Course | null = await fetchCourseBySlug(slug);

  if (!course) {
    return (
      <div className="container">
        <h1>Course not found</h1>
        <p className="muted">We couldn't find a course with that URL.</p>
      </div>
    );
  }

  const { pageTitle, introduction, image } = course.fields || {};
  const imageUrl = fixImageUrl(image?.fields?.file?.url);

  return (
    <div>
      <section className="course-hero">
        <div className="container">
          <div className="course-hero-grid">
            <div className="hero-content">
              <h1>{pageTitle}</h1>
              {introduction && <p className="hero-intro">{introduction}</p>}

              <div className="tags">
                <span className="badge">Self-paced</span>
                <span className="badge">Beginner</span>
                <span className="badge">CPD: 1.5h</span>
              </div>
            </div>

            <div className="hero-aside">
              <div className="course-card">
                {imageUrl ? (
                  // eslint-disable-next-line @next/next/no-img-element
                  <img src={imageUrl} alt={pageTitle || 'Course image'} className="course-image" />
                ) : (
                  <div style={{ height: 220, background: 'var(--color-muted)', borderRadius: 'var(--radius-sm)' }} />
                )}

                <div style={{ marginTop: 'var(--space-3)' }}>
                  <div className="meta-row">
                    <div>
                      <strong style={{ color: 'var(--color-text)' }}>{pageTitle}</strong>
                      <div className="muted">{course.sys?.id}</div>
                    </div>
                  </div>
                </div>

                <div style={{ marginTop: 'var(--space-4)' }} className="hero-cta">
                  <button className="btn">Enroll now</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      <div className="container">
        <div className="course-layout">
          <main>
            <div className="course-card">
              <h2>Overview</h2>
              <p className="muted">{introduction}</p>

              <section style={{ marginTop: 'var(--space-4)' }}>
                <h3>What you'll learn</h3>
                <p className="muted">Course content and learning objectives go here.</p>
              </section>
            </div>
          </main>

          <aside className="sidebar-card">
            <div className="course-card">
              <h3>Course details</h3>
              <div className="meta-row">
                <span className="muted">Duration: 1.5 hours</span>
              </div>
            </div>
          </aside>
        </div>
      </div>
    </div>
  );
}